from options import Options from time import * from physical import * from gpio import * from environment import Environment from ioeclient import IoEClient
autoCoolTemp = 20 autoHeatTemp = 19
METRIC = ""
HEATER_PIN = 1 COOLER_PIN = 2 state = 0 # 0 off, 1 cooling, 2 heating, 3 auto STATE_NAMES = ["OFF", "COOL", "HEAT", "AUTO"] temperature = 0 unit = ""
def setup (): global autoCoolTemp , autoHeatTemp , temperature , state
IoEClient.setup({ "type": "Thermostat", "states": [{ "name": "Status", "type": "options", "options": { 0: "Off", 1: "Cooling", 2: "Heating", 3: "Auto" }, "controllable": True }, { "name": "Temperature", "type": "number", "unit": "&deg;C", "imperialUnit": "&deg;F", "toImperialConversion": "x*1.8+32", "toMetricConversion": "(x-32)/1.8", "decimalDigits": 1 }, { "name": "Auto Cool Temperature", "type": "number", "unit": "&deg;C", "imperialUnit": "&deg;F", "toImperialConversion": "x*1.8+32", "toMetricConversion": "(x-32)/1.8", "decimalDigits": 1, "controllable": True, "minValue": 10, "maxValue": 100 }, { "name": "Auto Heat Temperature", "type": "number", "unit": "&deg;C", "imperialUnit": "&deg;F", "toImperialConversion": "x*1.8+32", "toMetricConversion": "(x-32)/1.8", "decimalDigits": 1, "controllable": True, "minValue": -100, "maxValue": 20 }] })
IoEClient.onInputReceive(on_input_receive)
add_event_detect(0, on_event_detect_0)
temperature = Environment.get("Ambient Temperature")
measurementSystemChangeEvent()
state = restoreProperty("state", 0) setState(state)
autoCoolTemp = restoreProperty("auto cool temp", 20) autoHeatTemp = restoreProperty("auto heat temp", 19)
Environment.removeCumulativeContribution("Ambient Temperature")
updateEnvironment() sendReport() on_event_detect_0()
def on_event_detect_0 () : processData(customRead(0), False)
def on_input_receive(input) : processData(input, True)
def restoreProperty (propertyName, defaultValue): value = getDeviceProperty(getName(), propertyName) if not (value == "" or value == None) : if isinstance(defaultValue, (int, float)) : value = int(value)
setDeviceProperty(getName(), propertyName, value) return value
return defaultValue
def loop (): global temperature temperature = Environment.get("Ambient Temperature") updateEnvironment() measurementSystemChangeEvent() sendReport() delay(1000)
def measurementSystemChangeEvent (): global METRIC, unit METRIC = Options.isUsingMetric() unit = "C" if METRIC else "F" setCustomText(27, 15, 200, 100, STATE_NAMES[state] + " " + convertTemperature(temperature) + " " + unit)
def mouseEvent (pressed, x, y, firstPress): global state # if mouse pressed, then flip it if firstPress: state+=1 if state >= 4: state = 0
setState(state)
def processData (data, bIsRemote): global autoCoolTemp, autoHeatTemp if data: # print data data = data.split(",") # print data[0],data[1],data[2],data[3] setState(int(data[0])) autoCoolTemp = float(data[2]) autoHeatTemp = float(data[3]) if autoCoolTemp < autoHeatTemp: autoCoolTemp,autoHeatTemp = autoHeatTemp,autoCoolTemp
def setState (newState): global state state = newState
analogWrite(A1, state) # change graphic setCustomText(27, 15, 200, 100, STATE_NAMES[state] + " " + convertTemperature(temperature) + " " + unit)
sendReport()
def sendReport (): report = str(state) + "," + str(temperature) + "," + str(autoCoolTemp) + "," + str(autoHeatTemp) customWrite(0, report) IoEClient.reportStates(report) setDeviceProperty(getName(), "state", state) # print "SR: ", autoCoolTemp, autoHeatTemp, temperature setDeviceProperty(getName(), "temperature", temperature) setDeviceProperty(getName(), "auto cool temp", autoCoolTemp) setDeviceProperty(getName(), "auto heat temp", autoHeatTemp)
def updateEnvironment (): global autoMode autoCoolTemp = float(getDeviceProperty(getName(), "auto cool temp")) autoHeatTemp = float(getDeviceProperty(getName(), "auto heat temp"))
digitalWrite(HEATER_PIN, LOW) digitalWrite(COOLER_PIN, LOW)
if state == 0 : digitalWrite(HEATER_PIN, LOW) digitalWrite(COOLER_PIN, LOW)
elif state == 1 : digitalWrite(COOLER_PIN, HIGH)
elif state == 2 : digitalWrite(HEATER_PIN, HIGH)
elif state == 3 : if temperature >= autoCoolTemp: digitalWrite(COOLER_PIN, HIGH)
elif temperature < autoHeatTemp: digitalWrite(HEATER_PIN, HIGH)
def convertTemperature (value): if METRIC: return "%.0f"%(value,) else: return "%.0f"%(value * 1.8 + 32,)
if __name__ == "__main__": setup() while True: loop()

