var autoCoolTemp = 20;
var autoHeatTemp = 19;

var METRIC;

var HEATER_PIN = 1;
var COOLER_PIN = 2;
var state = 0;	// 0 off, 1 cooling, 2 heating, 3 auto
var STATE_NAMES = ["OFF", "COOL", "HEAT", "AUTO"];
var temperature = 0;
var unit;


function setup () {
	IoEClient.setup({
		type: "Thermostat",
		states: [{
			name: "Status",
			type: "options",
			options: {
				"0": "Off",
				"1": "Cooling",
				"2": "Heating",
				"3": "Auto"
			},
			controllable: true
		}, {
			name: "Temperature",
			type: "number",
			unit: "&deg;C",
			imperialUnit: "&deg;F",
			toImperialConversion: "x*1.8+32",
			toMetricConversion: "(x-32)/1.8",
			decimalDigits: 1
		}, {
			name: "Auto Cool Temperature",
			type: "number",
			unit: "&deg;C",
			imperialUnit: "&deg;F",
			toImperialConversion: "x*1.8+32",
			toMetricConversion: "(x-32)/1.8",
			decimalDigits: 1,
			controllable: true,
			minValue: 10,
			maxValue: 100
		}, {
			name: "Auto Heat Temperature",
			type: "number",
			unit: "&deg;C",
			imperialUnit: "&deg;F",
			toImperialConversion: "x*1.8+32",
			toMetricConversion: "(x-32)/1.8",
			decimalDigits: 1,
			controllable: true,
			minValue: -100,
			maxValue: 20
		}]
	});

	IoEClient.onInputReceive = function(input) {
		processData(input, true);
	};

	attachInterrupt(0, function() {
		processData(customRead(0), false);
	});


	temperature = Environment.get("Ambient Temperature");

	measurementSystemChangeEvent();

	state = restoreProperty("state", 0);
	setState(state);

	autoCoolTemp = restoreProperty("auto cool temp", 20);
	autoHeatTemp = restoreProperty("auto heat temp", 19);




	Environment.removeCumulativeContribution("Ambient Temperature");

	updateEnvironment();
	sendReport();
	processData(customRead(0), false);
}

function restoreProperty (propertyName, defaultValue) {
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ) {
		if ( typeof(defaultValue) == "number" ) {
			value = Number(value);
        }

		setDeviceProperty(getName(), propertyName, value);
		return value;
	}

	return defaultValue;
}


function loop () {

	temperature = Environment.get("Ambient Temperature");
	updateEnvironment();
	measurementSystemChangeEvent();
	sendReport();
	delay(1000);
}

function measurementSystemChangeEvent () {
	METRIC = isUsingMetric();
	unit = METRIC ? "C" : "F";
	setCustomText(27, 15, 200, 100,
		STATE_NAMES[state] + "  " +
		convertTemperature(temperature) + " " + unit);		
}

function mouseEvent (pressed, x, y, firstPress) {
	// if mouse pressed, then flip it
	if (firstPress) {
		state++;
		if (state >= 4) {
			state = 0;
        }

		setState(state);
	}
}

function processData (data, bIsRemote) {
	if (data) {
		data = data.split(",");

		setState(parseInt(data[0]));
		autoCoolTemp = parseFloat(data[2]);
		autoHeatTemp = parseFloat(data[3]);
		if(autoHeatTemp > autoCoolTemp) {
			var t = autoCoolTemp
			autoCoolTemp = autoHeatTemp
			autoHeatTemp = t
		}
	}
}

function setState (newState) {
	state = newState;

	analogWrite(A1, state); // change graphic
	setCustomText(27, 15, 200, 100,
		STATE_NAMES[state] + "  " +
		convertTemperature(temperature) + " " + unit);		

	sendReport();

}

function sendReport () {
	var report = state + "," + temperature + ","
		+ autoCoolTemp + "," + autoHeatTemp;
	customWrite(0, report);
	IoEClient.reportStates(report);
	setDeviceProperty(getName(), "state", state);
	setDeviceProperty(getName(), "temperature", temperature);
	setDeviceProperty(getName(), "auto cool temp", autoCoolTemp);
	setDeviceProperty(getName(), "auto heat temp", autoHeatTemp);
}

function updateEnvironment ()
{
	var autoCoolTemp = getDeviceProperty(getName(), "auto cool temp");
	var autoHeatTemp = getDeviceProperty(getName(), "auto heat temp");

	digitalWrite(HEATER_PIN, LOW);
	digitalWrite(COOLER_PIN, LOW);

	if ( state === 0 ) {
		digitalWrite(HEATER_PIN, LOW);
		digitalWrite(COOLER_PIN, LOW);
	}
	else if ( state === 1 ) {
		digitalWrite(COOLER_PIN, HIGH);
	}
	else if ( state == 2 ) {
		digitalWrite(HEATER_PIN, HIGH);
	}
	else if ( state == 3 ) {
        if( temperature >= autoCoolTemp)
            digitalWrite(COOLER_PIN, HIGH);
        else if( temperature <= autoHeatTemp )
            digitalWrite(HEATER_PIN, HIGH);
	}
}

function convertTemperature (value) {
	if (METRIC) {
		return value.toFixed(0);
    } else {
		return (value * 1.8 + 32).toFixed(0);
    }
}

